#!/usr/bin/env python3
import subprocess
import sys
import os
import hashlib
import json
from pathlib import Path
from typing import Dict, Set, List
import tempfile
import shutil

class SecurePipInstaller:
    def __init__(self):
        self.requirements_file = "requirements.txt"
        self.lock_file = "requirements.lock"
        self.allowed_indexes = [
            "https://pypi.org/simple",
            "https://pypi.python.org/simple"
        ]
        self.max_file_size = 10 * 1024 * 1024  # 10MB
        
    def validate_requirements_file(self, filepath: str) -> bool:
        """Validate requirements file exists and is safe to read"""
        path = Path(filepath)
        
        if not path.exists():
            print(f"Error: Requirements file {filepath} not found", file=sys.stderr)
            return False
            
        if not path.is_file():
            print(f"Error: {filepath} is not a file", file=sys.stderr)
            return False
            
        if path.stat().st_size > self.max_file_size:
            print(f"Error: Requirements file exceeds maximum size", file=sys.stderr)
            return False
            
        try:
            with open(path, 'r', encoding='utf-8') as f:
                content = f.read()
                
            for line in content.splitlines():
                line = line.strip()
                if line and not line.startswith('#'):
                    if any(dangerous in line.lower() for dangerous in ['&&', '||', ';', '|', '`', '$(']):
                        print(f"Error: Potentially dangerous content in requirements file", file=sys.stderr)
                        return False
                        
        except Exception as e:
            print(f"Error reading requirements file: {e}", file=sys.stderr)
            return False
            
        return True
    
    def generate_lock_file(self) -> bool:
        """Generate lock file with package hashes for verification"""
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "freeze"],
                capture_output=True,
                text=True,
                check=True,
                timeout=60
            )
            
            packages = {}
            for line in result.stdout.splitlines():
                if '==' in line:
                    pkg_name, version = line.split('==', 1)
                    packages[pkg_name.strip()] = version.strip()
            
            with open(self.lock_file, 'w', encoding='utf-8') as f:
                json.dump({
                    'packages': packages,
                    'python_version': sys.version
                }, f, indent=2)
                
            print(f"Generated lock file: {self.lock_file}")
            return True
            
        except Exception as e:
            print(f"Warning: Could not generate lock file: {e}", file=sys.stderr)
            return False
    
    def verify_pip_integrity(self) -> bool:
        """Verify pip itself is properly installed"""
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "--version"],
                capture_output=True,
                text=True,
                check=True,
                timeout=30
            )
            print(f"Using pip: {result.stdout.strip()}")
            return True
        except Exception as e:
            print(f"Error: pip verification failed: {e}", file=sys.stderr)
            return False
    
    def install_with_constraints(self) -> bool:
        """Install packages with security constraints"""
        if not self.validate_requirements_file(self.requirements_file):
            return False
            
        if not self.verify_pip_integrity():
            return False
        
        install_cmd = [
            sys.executable, "-m", "pip", "install",
            "-r", self.requirements_file,
            "--upgrade",
            "--no-cache-dir",
            "--require-hashes" if os.path.exists(self.requirements_file + ".hashed") else "--only-binary=:all:",
            "--index-url", self.allowed_indexes[0],
            "--trusted-host", "pypi.org",
            "--trusted-host", "pypi.python.org",
            "--trusted-host", "files.pythonhosted.org"
        ]
        
        if not os.path.exists(self.requirements_file + ".hashed"):
            install_cmd.remove("--require-hashes")
            install_cmd.remove("--only-binary=:all:")
            print("Warning: Installing without hash verification. Consider using hashed requirements for production.")
        
        try:
            env = os.environ.copy()
            env.pop('PIP_INDEX_URL', None)
            env.pop('PIP_EXTRA_INDEX_URL', None)
            env['PYTHONHASHSEED'] = '0'
            
            print(f"Installing packages from {self.requirements_file}...")
            result = subprocess.run(
                install_cmd,
                env=env,
                check=True,
                timeout=600,
                capture_output=False
            )
            
            print("Package installation completed successfully")
            self.generate_lock_file()
            return True
            
        except subprocess.TimeoutExpired:
            print("Error: Installation timed out", file=sys.stderr)
            return False
        except subprocess.CalledProcessError as e:
            print(f"Error: Installation failed with exit code {e.returncode}", file=sys.stderr)
            return False
        except Exception as e:
            print(f"Error: Unexpected error during installation: {e}", file=sys.stderr)
            return False
    
    def verify_installed_packages(self) -> bool:
        """Verify installed packages match requirements"""
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "check"],
                capture_output=True,
                text=True,
                timeout=60
            )
            
            if result.returncode != 0:
                print(f"Warning: Package dependency issues detected:\n{result.stdout}", file=sys.stderr)
                return False
                
            print("Package verification passed")
            return True
            
        except Exception as e:
            print(f"Warning: Could not verify packages: {e}", file=sys.stderr)
            return False

def main():
    installer = SecurePipInstaller()
    
